/**
 * @fileoverview Breadcrumb barrel.
 * @module module/Breadcrumb
 */
import { default as razyui } from '../index.js';
import { BreadcrumbDef as DEF } from './Breadcrumb.def.js';
import Breadcrumb from './Breadcrumb/index.js';

razyui.Breadcrumb = Breadcrumb;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Breadcrumb);
}

export default Breadcrumb;

export const stylesheet = null;
