/**
 * @fileoverview Breadcrumb view — DOM rendering.
 * @module module/Breadcrumb/view
 */

import { CLS, PART } from './constants.js';

export function renderDOM(root, items, separator) {
    const el = root[0];
    el.innerHTML = '';

    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    const nav = document.createElement('nav');
    nav.setAttribute('aria-label', 'Breadcrumb');

    const $ol = PART.LIST.create();
    nav.appendChild($ol[0]);  // nav is raw DOM, no Elements wrapper

    items.forEach((item, i) => {
        const isLast = i === items.length - 1;

        const $li = PART.ITEM.create();
        $ol.append($li);

        // Link or span
        let linkEl;
        if (item.href && !isLast) {
            linkEl = document.createElement('a');
            linkEl.href = item.href;
        } else {
            linkEl = document.createElement('span');
            if (isLast) linkEl.setAttribute('aria-current', 'page');
        }

        linkEl.className = CLS.LINK;
        if (isLast) linkEl.classList.add(CLS.CURRENT);
        linkEl.textContent = item.label;
        $li.append(linkEl);

        const $link = PART.LINK.apply(linkEl);
        if (isLast) $link.addClass(CLS.CURRENT);

        // Separator (not after last item)
        if (!isLast) {
            const $sep = PART.SEPARATOR.create({ 'aria-hidden': 'true' });
            $sep.text(separator);
            $li.append($sep);
        }
    });

    root.append(nav);
}

export function cleanupDOM(root) {
    root.removeClass(CLS.ROOT);
}
