/**
 * @fileoverview Breadcrumb constants.
 * @module module/Breadcrumb/constants
 */

import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT:      'breadcrumb',
    LIST:      'breadcrumb-list',
    ITEM:      'breadcrumb-item',
    LINK:      'breadcrumb-link',
    SEPARATOR: 'breadcrumb-sep',
    CURRENT:   'is-current',
});

export const DEFAULTS = Object.freeze({
    items: [],        // [{ label, href? }]
    separator: '/',
});

export const PART = defineParts('Breadcrumb', {
    ROOT:      { class: 'breadcrumb-root', aliases: ['root'] },
    LIST:      { class: 'breadcrumb-list', aliases: ['list'], tag: 'ol' },
    ITEM:      { class: 'breadcrumb-item', aliases: ['item'], tag: 'li' },
    LINK:      { class: 'breadcrumb-link', aliases: ['link'] },
    SEPARATOR: { class: 'breadcrumb-sep', aliases: ['separator', 'sep'], tag: 'span' },
});

PART.ROOT.jit      = '[font-family:var(--bc-font-stack)] text-[var(--bc-font-size)]';
PART.LIST.jit      = 'flex items-center gap-[var(--bc-gap)] list-none m-0 p-0';
PART.ITEM.jit      = 'flex items-center gap-[var(--bc-gap)]';
PART.LINK.jit      = 'fg-[var(--bc-link-color)] text-decoration-none hover:fg-[var(--bc-link-hover)] hover:underline {is-current}:fg-[var(--bc-current-color)] {is-current}:font-medium {is-current}:pointer-events-none';
PART.SEPARATOR.jit = 'fg-[var(--bc-sep-color)] select-none';
